"const fs = require('fs');
const path = require('path');
const readline = require('readline');

const logPath = 'C:\\Users\\paloptical\\.gemini\\antigravity\\brain\\f89774ed-f905-432d-8902-e9fb55f69e45\\.system_generated\\logs\\transcript.jsonl';

const rl = readline.createInterface({
  input: fs.createReadStream(logPath),
  crlfDelay: Infinity
});

let foundCount = 0;

rl.on('line', (line) => {
  try {
    const data = JSON.parse(line);

    // Look for tool outputs from view_file tool on App.tsx
    // The logs might contain the content of the file
    if (data.type === 'tool_result' || data.type === 'TOOL_RESULT' || (data.content && data.content.includes('PatientInfoForm') && data.content.includes('export const App'))) {
      if (typeof data.content === 'string' && data.content.includes('export const App') && data.content.includes('1: import')) {
        console.log(`Found matching step: ${data.step_index}`);
        fs.writeFileSync(`app_tsx_backup_${data.step_index}.txt`, data.content);
        foundCount++;
      }
    }
  } catch (err) {
    // Ignore JSON parse errors
  }
});

rl.on('close', () => {
  console.log(`Finished processing. Found ${foundCount} backups.`);
});
"
